krpano.action:
set(data[greenscreen_settings].current, '');
set(data[greenscreen_settings].candidate, '');
set(data[greenscreen_settings].suppressed, '');
set(data[greenscreen_settings].manual, false);
set(data[greenscreen_settings].running, true);
delayedcall(greenscreen_loop, get(data[greenscreen_settings].check_interval), greenscreen_check_loop(); );

for(set(_gs_i, 0), _gs_i LT hotspot.count, inc(_gs_i),
	copy(_gs_name, hotspot[get(_gs_i)].name);
	if(hotspot[get(_gs_name)].editor_type == 'greenscreen' OR hotspot[get(_gs_name)].greenscreen_autoplay == true,
		if(hotspot[get(_gs_name)].pause, hotspot[get(_gs_name)].pause(); );
	);
);
set(data[greenscreen_settings].current, '');

set(_gs_target, %1);
set(_gs_source, %2);
for(set(_gs_i, 0), _gs_i LT hotspot.count, inc(_gs_i),
	copy(_gs_name, hotspot[get(_gs_i)].name);
	if(hotspot[get(_gs_name)].editor_type == 'greenscreen' OR hotspot[get(_gs_name)].greenscreen_autoplay == true,
		if(_gs_name == _gs_target,

			if(hotspot[get(_gs_name)].ispaused == true,
				hotspot[get(_gs_name)].togglepause();
			);
		,
			if(hotspot[get(_gs_name)].pause, hotspot[get(_gs_name)].pause(); );
		);
	);
);
copy(data[greenscreen_settings].current, _gs_target);
set(data[greenscreen_settings].suppressed, '');
if(_gs_source == 'manual',
	set(data[greenscreen_settings].manual, true);
	set(data[greenscreen_settings].autoplay_unlocked, true);
	stopdelayedcall(greenscreen_manual_unlock);
	delayedcall(greenscreen_manual_unlock, get(data[greenscreen_settings].manual_lock_seconds), set(data[greenscreen_settings].manual, false); );
,
	set(data[greenscreen_settings].manual, false);
	stopdelayedcall(greenscreen_manual_unlock);
);

if(hotspot[%1].pause, hotspot[%1].pause(); );
set(data[greenscreen_settings].suppressed, %1);
if(data[greenscreen_settings].current == %1,
	set(data[greenscreen_settings].current, '');
	set(data[greenscreen_settings].manual, false);
	stopdelayedcall(greenscreen_manual_unlock);
);

calc(_gs_dh, %1 - view.hlookat);
if(_gs_dh GT 180, sub(_gs_dh, 360));
if(_gs_dh LT -180, add(_gs_dh, 360));
calc(_gs_dh, abs(_gs_dh));
set(global.greenscreen_tmp_dh, get(_gs_dh));

set(global.greenscreen_tmp_in_view, false);
if(hotspot[%1],
	greenscreen_get_delta_h(get(hotspot[%1].ath));
	copy(_gs_hdiff, global.greenscreen_tmp_dh);
	calc(_gs_vdiff, abs(hotspot[%1].atv - view.vlookat));
	calc(_gs_hlimit, view.fov * data[greenscreen_settings].h_factor);
	calc(_gs_vlimit, view.fov * data[greenscreen_settings].v_factor);
	if(_gs_hdiff LT _gs_hlimit AND _gs_vdiff LT _gs_vlimit,
		set(global.greenscreen_tmp_in_view, true);
	);
);

set(global.greenscreen_best, '');
set(_gs_best_score, 999999);
for(set(_gs_i, 0), _gs_i LT hotspot.count, inc(_gs_i),
	copy(_gs_name, hotspot[get(_gs_i)].name);
	if(hotspot[get(_gs_name)].editor_type == 'greenscreen' OR hotspot[get(_gs_name)].greenscreen_autoplay == true,
		greenscreen_get_delta_h(get(hotspot[get(_gs_name)].ath));
		copy(_gs_hdiff, global.greenscreen_tmp_dh);
		calc(_gs_vdiff, abs(hotspot[get(_gs_name)].atv - view.vlookat));
		calc(_gs_hlimit, view.fov * data[greenscreen_settings].h_factor);
		calc(_gs_vlimit, view.fov * data[greenscreen_settings].v_factor);
		if(_gs_hdiff LT _gs_hlimit AND _gs_vdiff LT _gs_vlimit,
			calc(_gs_score, _gs_hdiff + _gs_vdiff * 1.5);
			if(_gs_score LT _gs_best_score,
				copy(_gs_best_score, _gs_score);
				set(global.greenscreen_best, get(_gs_name));
			);
		);
	);
);

copy(_gs_candidate, data[greenscreen_settings].candidate);
if(_gs_candidate != '',
	greenscreen_find_best();
	copy(_gs_best_now, global.greenscreen_best);
	if(_gs_best_now == _gs_candidate,
		greenscreen_play_only(get(_gs_candidate), auto);
	);
);
set(data[greenscreen_settings].candidate, '');

set(_gs_skip_auto, false);
if(data[greenscreen_settings].manual == true,
	copy(_gs_current, data[greenscreen_settings].current);
	greenscreen_is_in_view(get(_gs_current));
	copy(_gs_manual_in_view, global.greenscreen_tmp_in_view);
	if(_gs_manual_in_view == true,
		set(_gs_skip_auto, true);
	,
		set(data[greenscreen_settings].manual, false);
		stopdelayedcall(greenscreen_manual_unlock);
	);
);


copy(_gs_keep, data[greenscreen_settings].current);
if(_gs_keep != '' AND data[greenscreen_settings].suppressed != _gs_keep,
	if(hotspot[get(_gs_keep)].ispaused == true AND hotspot[get(_gs_keep)].loaded == true,
		hotspot[get(_gs_keep)].togglepause();
	);
);


if(data[greenscreen_settings].autoplay_unlocked != true,
	set(_gs_skip_auto, true);
);

if(_gs_skip_auto == false,
	greenscreen_find_best();
	copy(_gs_best, global.greenscreen_best);
	if(_gs_best == '',
		greenscreen_stop_all();
		set(data[greenscreen_settings].candidate, '');
		set(data[greenscreen_settings].suppressed, '');
		stopdelayedcall(greenscreen_auto_commit_delay);
	,
		if(_gs_best == data[greenscreen_settings].suppressed,

			set(data[greenscreen_settings].candidate, '');
			stopdelayedcall(greenscreen_auto_commit_delay);
		,
			set(data[greenscreen_settings].suppressed, '');
			if(data[greenscreen_settings].current == _gs_best,
				set(data[greenscreen_settings].candidate, '');
				stopdelayedcall(greenscreen_auto_commit_delay);
			,
				if(data[greenscreen_settings].candidate != _gs_best,
					copy(data[greenscreen_settings].candidate, _gs_best);
					stopdelayedcall(greenscreen_auto_commit_delay);
					delayedcall(greenscreen_auto_commit_delay, get(data[greenscreen_settings].switch_delay), greenscreen_commit_candidate(); );
				);
			);
		);
	);
);
